arguments.command:
$REPO = "edburns/Build26-BRK206-your-agent-anywhere-multiclient-multidevice-with-github-copilot-sdk"
$BRANCH = "copilot/edburns28-python-agent-demo-remove-before-merge"
$PR_NUMBER = "47"
$TIMEOUT = 900
$INTERVAL = 30
$ELAPSED = 0

Write-Host "Waiting for Copilot agent to finish and CI runs to appear..."

while ($ELAPSED -lt $TIMEOUT) {
    # Check if the Copilot agent run is still in progress
    $runs = gh run list -R $REPO --branch $BRANCH --json databaseId,name,status,conclusion 2>$null | ConvertFrom-Json

    $agentRun = $runs | Where-Object { $_.name -eq "Running Copilot cloud agent" }
    $otherRuns = $runs | Where-Object { $_.name -ne "Running Copilot cloud agent" }

    if ($agentRun) {
        Write-Host "[$ELAPSED s] Agent status: $($agentRun.status) / $($agentRun.conclusion)"
    }

    # Check for action_required runs
    $actionRequired = $runs | Where-Object { $_.status -eq "action_required" }
    if ($actionRequired) {
        Write-Host "Found runs needing approval:"
        $actionRequired | ForEach-Object { Write-Host "  Run $($_.databaseId): $($_.name)" }
        break
    }

    # Check if other CI runs appeared (completed or in progress)
    if ($otherRuns -and $otherRuns.Count -gt 0) {
        Write-Host "CI runs appeared:"
        $otherRuns | ForEach-Object { Write-Host "  Run $($_.databaseId): $($_.name) - $($_.status)" }
        break
    }

    # If agent is completed but no other runs yet, keep waiting briefly
    if ($agentRun -and $agentRun.status -eq "completed") {
        Write-Host "Agent completed, waiting for CI runs to trigger..."
    }

    Start-Sleep -Seconds $INTERVAL
    $ELAPSED += $INTERVAL
}

if ($ELAPSED -ge $TIMEOUT) {
    Write-Host "TIMEOUT: No CI runs appeared after $TIMEOUT seconds"
}

# Final state
Write-Host "`nFinal run list:"
gh run list -R $REPO --branch $BRANCH --json databaseId,name,status,conclusion --jq '.[] | "\(.databaseId) | \(.name) | \(.status) | \(.conclusion)"'

